module top_module(
    output reg INV_Q,
    input S,
    input R,
    input D,
    input G,
    input E
);parameter [0:0] INIT = 1'b0;
    parameter [0:0] IS_C_INVERTED = 1'b0;

    initial INV_Q = INIT;

    always @*
    begin
        if (R) INV_Q <= 1'b0;
        else if (S) INV_Q <= 1'b1;
        else if (E && G) INV_Q <= D;
    end

endmodule
